mapper.select:
/* com.erns.coching.message.mapper.MessageDAO.getListVo */

SELECT

FROM T_MESSAGE_INF AA





	OFFSET #{offset} LIMIT #{rowSize}

/* com.erns.coching.message.mapper.MessageDAO.getList */
SELECT ZZ.* FROM ( SELECT
, SS.MEMB_NAME AS SENDER_NAME , RR.MEMB_NAME AS RECEIVER_NAME FROM T_MESSAGE_INF AA
LEFT OUTER JOIN T_MESSAGE_BLOCK BB ON BB.memb_seq = #{userMembSeq, jdbcType=INTEGER} AND AA.sender != BB.block_seq /* 차단 사용자*/
LEFT OUTER JOIN T_MEMB_INF SS ON AA.SENDER = SS.MEMB_SEQ LEFT OUTER JOIN T_MEMB_INF RR ON AA.RECEIVER = RR.MEMB_SEQ
AND AA.SENDER = #{userMembSeq, jdbcType=INTEGER} AND COALESCE(AA.SENDER_DEL_YN, 'N') = 'N'
AND AA.RECEIVER = #{userMembSeq, jdbcType=INTEGER} AND COALESCE(AA.RECEIVER_DEL_YN, 'N') = 'N'
ORDER BY CASE WHEN AA.STATE = '0' THEN 1 ELSE 2 END, -- STATE가 0인 것을 우선 AA.RGT_DTTM DESC
) ZZ
OFFSET #{offset} LIMIT #{rowSize}

	/* com.erns.coching.message.mapper.MessageDAO.getListCount */

SELECT COUNT(*)
FROM T_MESSAGE_INF AA

	LEFT OUTER JOIN T_MESSAGE_BLOCK BB 
		ON BB.memb_seq = #{userMembSeq, jdbcType=INTEGER}
		AND AA.sender != BB.block_seq
	/* 차단 사용자*/




		AND AA.SENDER = #{userMembSeq, jdbcType=INTEGER}
		AND COALESCE(AA.SENDER_DEL_YN, 'N') = 'N'


		AND AA.RECEIVER = #{userMembSeq, jdbcType=INTEGER}
		AND COALESCE(AA.RECEIVER_DEL_YN, 'N') = 'N'

	/* com.erns.coching.message.mapper.MessageDAO.load */

SELECT

FROM T_MESSAGE_INF AA

	LEFT OUTER JOIN T_MESSAGE_BLOCK BB 
		ON BB.memb_seq = #{userMembSeq, jdbcType=INTEGER}
		AND AA.sender != BB.block_seq
	/* 차단 사용자*/


	AND AA.MESSAGE_SEQ = #{messageSeq, jdbcType=INTEGER}		


		AND AA.SENDER = #{userMembSeq, jdbcType=INTEGER}
		AND COALESCE(AA.SENDER_DEL_YN, 'N') = 'N'


		AND AA.RECEIVER = #{userMembSeq, jdbcType=INTEGER}
		AND COALESCE(AA.RECEIVER_DEL_YN, 'N') = 'N'

mapper.update:
	/* com.erns.coching.message.mapper.MessageDAO.updateState */

UPDATE T_MESSAGE_INF SET
	STATE							= COALESCE(#{state	, jdbcType=VARCHAR}, '0')

	AND MESSAGE_SEQ		= #{messageSeq	, jdbcType=INTEGER}

	/* com.erns.coching.message.mapper.MessageDAO.updateSenderDelYn */

UPDATE T_MESSAGE_INF SET
		SENDER_DEL_YN 	= #{senderDelYn	, jdbcType=CHAR}			

	AND MESSAGE_SEQ		= #{messageSeq	, jdbcType=INTEGER}
	AND SENDER			= #{sender		, jdbcType=INTEGER}

	/* com.erns.coching.message.mapper.MessageDAO.updateReceiverDelYn */

UPDATE T_MESSAGE_INF SET
		RECEIVER_DEL_YN 	= #{receiverDelYn	, jdbcType=CHAR}

	AND MESSAGE_SEQ			= #{messageSeq	, jdbcType=INTEGER}
	AND RECEIVER			= #{receiver	, jdbcType=INTEGER}

mapper.delete:
/* com.erns.coching.message.mapper.MessageDAO.delete */

DELETE FROM T_MESSAGE_INF

	AND MESSAGE_SEQ 	= #{messageSeq	, jdbcType=INTEGER}
